import undetected_chromedriver as ucimport jsonimport timeoptions = uc.ChromeOptions()driver = uc.Chrome(options=options)print("🚀 Starting browser...")driver.get("https://flightpass.royalairmaroc.com")time.sleep(3)print("📂 Loading cookies from file...")with open("cookies.json", "r") as f:    cookies = json.load(f)driver.delete_all_cookies()for cookie in cookies:    cookie.pop('sameSite', None)    try:        driver.add_cookie(cookie)    except Exception as e:        print(f"⚠️ Cookie error: {cookie.get('name')}, {e}")print("📥 Injecting localStorage...")with open("local_storage.json", "r") as f:    local_storage = json.load(f)for key, value in local_storage.items():    driver.execute_script(f"window.localStorage.setItem('{key}', '{value}');")print("📥 Injecting sessionStorage...")with open("session_storage.json", "r") as f:    session_storage = json.load(f)for key, value in session_storage.items():    driver.execute_script(f"window.sessionStorage.setItem('{key}', '{value}');")print("🔄 Refreshing page to apply cookies and storage...")driver.refresh()time.sleep(5)print("➡️ Navigating to your account page...")driver.get("https://flightpass.royalairmaroc.com/?lg=fr")time.sleep(5)input("✅ Done! Check the browser. If you see your name/account, it's working! Press Enter to close.")driver.quit()